1	// Mutation hardening tests — separate from unit and acceptance suites.
2	// Each test targets a specific surviving mutant identified by cargo-mutants.
3	
4	use drywall::ast::{
5	    RUST_CONFIG, build_normalized_subtree, extract_functions, extract_let_declaration, make_parser,
6	};
7	use drywall::scan::{build_glob_set, collect_from_directory};
8	use drywall::{FunctionInfo, find_duplicate_pairs, jaccard, source_lines};
9	use std::fs;
10	
11	fn parse_and_extract(source: &str) -> Vec<FunctionInfo> {
12	    let tree = make_parser().parse(source, None).unwrap();
13	    let mut functions = Vec::new();
14	    extract_functions(tree.root_node(), source, "test.rs", &mut functions);
15	    functions
16	}
17	
18	fn make_fi(start_line: usize, end_line: usize, hashes: Vec<u64>) -> FunctionInfo {
19	    FunctionInfo {
20	        file: "test.rs".to_string(),
21	        start_line,
22	        end_line,
23	        node_hashes: hashes,
24	    }
25	}
26	
27	// --- ast.rs:55 --- extract_let_declaration: child.kind() != "closure_expression"
28	// Mutant: replace != with ==
29	// Guard: a closure containing a nested closure must yield only 1 entry (the outer let-bound
30	// closure). If != became ==, we'd recurse INTO the outer closure's children, potentially
31	// finding and registering the inner closure as a second function. Verify we do NOT double-count.
32	#[test]
33	fn let_decl_nested_closure_not_double_counted() {
34	    // A let with a closure that itself contains another let-bound closure inside its body.
35	    // With != mutated to ==: we'd recurse into the outer closure_expression, find the inner
36	    // let_declaration, and push a second function entry.
37	    let source = "let outer = |x: i32| -> i32 { let inner = |y: i32| y + 1; inner(x) };\n";
38	    let tree = make_parser().parse(source, None).unwrap();
39	    let mut functions = Vec::new();
40	    let root = tree.root_node();
41	    let mut cursor = root.walk();
42	    let children: Vec<_> = root.children(&mut cursor).collect();
43	    if let Some(let_node) = children.iter().find(|n| n.kind() == "let_declaration") {
44	        extract_let_declaration(*let_node, source, "test.rs", &mut functions);
45	    }
46	    assert_eq!(
47	        functions.len(),
48	        1,
49	        "only the outer closure should be captured, got {} entries",
50	        functions.len()
51	    );
52	}
53	
54	// Verify that non-closure let children ARE traversed (extract nested fn items from sub-nodes).
55	#[test]
56	fn let_decl_non_closure_children_are_traversed() {
57	    // A plain let that contains no closure; the extract_let_declaration should not add anything,
58	    // but it must not prevent traversal of other children.
59	    let source = "let x = 42;\n";
60	    let tree = make_parser().parse(source, None).unwrap();
61	    let mut functions = Vec::new();
62	    let root = tree.root_node();
63	    let mut cursor = root.walk();
64	    let children: Vec<_> = root.children(&mut cursor).collect();
65	    if let Some(let_node) = children.iter().find(|n| n.kind() == "let_declaration") {
66	        extract_let_declaration(*let_node, source, "test.rs", &mut functions);
67	    }
68	    assert_eq!(functions.len(), 0);
69	}
70	
71	// --- ast.rs:34 --- delete match arm "let_declaration" in extract_functions
72	// Mutant: if the let_declaration arm is deleted, extract_functions falls to the _ arm which
73	// recurses into children — but never calls extract_let_declaration, so let-bound closures
74	// are never captured as functions.
75	#[test]
76	fn extract_functions_captures_let_bound_closure() {
77	    // extract_functions must find the closure in a top-level let statement.
78	    // If the let_declaration arm is deleted, the closure is never pushed.
79	    let source = "let f = |x: i32| -> i32 { x + 1 };\n";
80	    let functions = parse_and_extract(source);
81	    assert_eq!(
82	        functions.len(),
83	        1,
84	        "let-bound closure must be captured by extract_functions, got {}",
85	        functions.len()
86	    );
87	}
88	
89	// --- ast.rs:75 --- make_function_info: start_line = row + 1 (mutation: + -> *)
90	// Guard: tree-sitter rows are 0-based; +1 makes them 1-based. For a top-level function on row 0,
91	// start_line must be 1 (not 0, which * would produce: 0*1=0).
92	#[test]
93	fn make_function_info_start_line_is_one_based() {
94	    let source = "fn top() {}\n";
95	    let functions = parse_and_extract(source);
96	    assert_eq!(functions.len(), 1);
97	    assert_eq!(
98	        functions[0].start_line, 1,
99	        "start_line must be 1-based (row 0 + 1), got {}",
100	        functions[0].start_line
101	    );
102	}
103	
104	// For a function on row 2 (third line), start_line must be 3, not 6 (which * would give: 2*3=6).
105	#[test]
106	fn make_function_info_start_line_correct_for_non_zero_row() {
107	    let source = "\n\nfn third_row() {}\n";
108	    let functions = parse_and_extract(source);
109	    assert_eq!(functions.len(), 1);
110	    assert_eq!(
111	        functions[0].start_line, 3,
112	        "start_line for row 2 must be 3 (2+1), got {}",
113	        functions[0].start_line
114	    );
115	}
116	
117	// --- ast.rs:89 --- normalize_node_text: literal match arm deletion
118	// Guard: integer/float/string/char/bool literals must normalize to _LIT so that structurally
119	// identical functions with different literal values still get high Jaccard scores.
120	#[test]
121	fn normalize_literal_integers_are_replaced() {
122	    // Two functions differing only in integer literals must have the same normalized subtree hash.
123	    let source_a = "fn a() -> i32 { 42 }\n";
124	    let source_b = "fn b() -> i32 { 99 }\n";
125	    let tree_a = make_parser().parse(source_a, None).unwrap();
126	    let tree_b = make_parser().parse(source_b, None).unwrap();
127	    let norm_a = build_normalized_subtree(tree_a.root_node(), source_a, &RUST_CONFIG);
128	    let norm_b = build_normalized_subtree(tree_b.root_node(), source_b, &RUST_CONFIG);
129	    assert_eq!(
130	        norm_a, norm_b,
131	        "functions differing only in integer literals must normalize identically"
132	    );
133	}
134	
135	#[test]
136	fn normalize_float_literals_are_replaced() {
137	    // float_literal is a leaf in tree-sitter-rust (like integer_literal).
138	    let source_a = "fn a() -> f64 { 1.5 }\n";
139	    let source_b = "fn b() -> f64 { 9.9 }\n";
140	    let tree_a = make_parser().parse(source_a, None).unwrap();
141	    let tree_b = make_parser().parse(source_b, None).unwrap();
142	    let norm_a = build_normalized_subtree(tree_a.root_node(), source_a, &RUST_CONFIG);
143	    let norm_b = build_normalized_subtree(tree_b.root_node(), source_b, &RUST_CONFIG);
144	    assert_eq!(
145	        norm_a, norm_b,
146	        "functions differing only in float literals must normalize identically"
147	    );
148	}
149	
150	#[test]
