1	use crate::ast::{LangConfig, extract_functions_with_config, lang_config, parse_source_tree_for};
2	use crate::core::{FunctionInfo, Lang};
3	use globset::{Glob, GlobSet, GlobSetBuilder};
4	use std::path::{Component, Path};
5	use std::process::Command;
6	use walkdir::WalkDir;
7	
8	const BUILTIN_EXCLUDED_DIRS: &[&str] = &[
9	    ".git",
10	    "target",
11	    "node_modules",
12	    "__pycache__",
13	    "vendor",
14	    "dist",
15	    ".next",
16	];
17	
18	pub fn is_builtin_excluded(path: &Path) -> bool {
19	    path.components().any(|c| {
20	        if let Component::Normal(name) = c {
21	            BUILTIN_EXCLUDED_DIRS.contains(&name.to_str().unwrap_or(""))
22	        } else {
23	            false
24	        }
25	    })
26	}
27	
28	fn git_check_ignore(path: &Path) -> Option<bool> {
29	    let abs = path.canonicalize().ok()?;
30	    let parent = abs.parent()?;
31	    let output = Command::new("git")
32	        .args([
33	            "-C",
34	            &parent.to_string_lossy(),
35	            "check-ignore",
36	            "--",
37	            &abs.to_string_lossy(),
38	        ])
39	        .output()
40	        .ok()?;
41	    Some(output.status.code() == Some(0))
42	}
43	
44	pub fn is_git_ignored(path: &Path) -> bool {
45	    git_check_ignore(path).unwrap_or(false)
46	}
47	
48	pub fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
49	    let mut builder = GlobSetBuilder::new();
50	    for pat in patterns {
51	        builder.add(Glob::new(pat)?);
52	    }
53	    builder.build()
54	}
55	
56	const EXT_LANG_MAP: &[(&str, Lang)] = &[
57	    ("rs", Lang::Rust),
58	    ("js", Lang::JavaScript),
59	    ("jsx", Lang::JavaScript),
60	    ("ts", Lang::TypeScript),
61	    ("tsx", Lang::Tsx),
62	];
63	
64	pub fn detect_lang(path: &Path) -> Option<Lang> {
65	    let ext = path.extension().and_then(|e| e.to_str())?;
66	    EXT_LANG_MAP.iter().find(|(e, _)| *e == ext).map(|(_, l)| *l)
67	}
68	
69	pub fn is_rust_file(path: &Path) -> bool {
70	    path.extension().and_then(|e| e.to_str()) == Some("rs")
71	}
72	
73	pub fn is_supported_file(path: &Path) -> bool {
74	    detect_lang(path).is_some()
75	}
76	
77	pub fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
78	    if exclude_set.is_empty() {
79	        return false;
80	    }
81	    exclude_set.is_match(path)
82	}
83	
84	/// Returns whether a file should be scanned.
85	/// When force_lang is Some, every non-excluded, non-builtin-excluded file is scanned.
86	/// When force_lang is None, only files with recognized extensions are scanned.
87	pub fn should_scan_file(
88	    path: &Path,
89	    exclude_set: &GlobSet,
90	    git_ignored: &dyn Fn(&Path) -> bool,
91	    force_lang: Option<Lang>,
92	) -> bool {
93	    if is_builtin_excluded(path) || should_skip(path, exclude_set) || git_ignored(path) {
94	        return false;
95	    }
96	    match force_lang {
97	        Some(_) => true,
98	        None => is_supported_file(path),
99	    }
100	}
101	
102	pub fn collect_all_functions(
103	    paths: &[String],
104	    exclude_set: &GlobSet,
105	    force_lang: Option<Lang>,
106	) -> (Vec<FunctionInfo>, Vec<String>) {
107	    let mut functions: Vec<FunctionInfo> = Vec::new();
108	    let mut errors: Vec<String> = Vec::new();
109	    for path_str in paths {
110	        let path = Path::new(path_str);
111	        if !path.exists() {
112	            errors.push(format!("path does not exist: {}", path_str));
113	        } else {
114	            collect_functions_from_path(path, exclude_set, force_lang, &mut functions, &mut errors);
115	        }
116	    }
117	    (functions, errors)
118	}
119	
120	pub fn collect_functions_from_path(
121	    path: &Path,
122	    exclude_set: &GlobSet,
123	    force_lang: Option<Lang>,
124	    functions: &mut Vec<FunctionInfo>,
125	    errors: &mut Vec<String>,
126	) {
127	    if path.is_file() {
128	        collect_from_single_file(path, exclude_set, force_lang, functions, errors);
129	    } else {
130	        collect_from_directory(path, exclude_set, force_lang, functions, errors);
131	    }
132	}
133	
134	pub fn collect_from_single_file(
135	    path: &Path,
136	    exclude_set: &GlobSet,
137	    force_lang: Option<Lang>,
138	    functions: &mut Vec<FunctionInfo>,
139	    errors: &mut Vec<String>,
140	) {
141	    if should_scan_file(path, exclude_set, &is_git_ignored, force_lang) {
142	        let lang = force_lang.or_else(|| detect_lang(path)).unwrap();
143	        process_file(path, lang, functions, errors);
144	    }
145	}
146	
147	fn process_entry(
148	    entry: Result<walkdir::DirEntry, walkdir::Error>,
149	    exclude_set: &GlobSet,
150	    force_lang: Option<Lang>,
151	    functions: &mut Vec<FunctionInfo>,
152	    errors: &mut Vec<String>,
153	) {
154	    match entry {
155	        Ok(e)
156	            if e.file_type().is_file()
157	                && should_scan_file(e.path(), exclude_set, &is_git_ignored, force_lang) =>
158	        {
159	            let lang = force_lang.or_else(|| detect_lang(e.path())).unwrap();
160	            process_file(e.path(), lang, functions, errors);
161	        }
162	        Ok(_) => {}
163	        Err(err) => errors.push(format!("walk error: {}", err)),
164	    }
165	}
166	
167	pub fn collect_from_directory(
168	    path: &Path,
169	    exclude_set: &GlobSet,
170	    force_lang: Option<Lang>,
171	    functions: &mut Vec<FunctionInfo>,
172	    errors: &mut Vec<String>,
173	) {
174	    let walker = WalkDir::new(path)
175	        .sort_by_file_name()
176	        .into_iter()
177	        .filter_entry(|e| !e.file_type().is_dir() || !is_builtin_excluded(e.path()));
178	    for entry in walker {
179	        process_entry(entry, exclude_set, force_lang, functions, errors);
180	    }
181	}
182	
183	pub fn process_file(
184	    path: &Path,
185	    lang: Lang,
186	    functions: &mut Vec<FunctionInfo>,
187	    errors: &mut Vec<String>,
188	) {
189	    let source = match std::fs::read_to_string(path) {
190	        Ok(s) => s,
191	        Err(e) => {
192	            errors.push(format!("cannot read {}: {}", path.display(), e));
193	            return;
194	        }
195	    };
196	
197	    let config: &LangConfig = lang_config(lang);
198	    match parse_source_tree_for(&source, lang) {
199	        Ok(tree) => {
200	            let file_str = path.to_string_lossy().to_string();
201	            extract_functions_with_config(tree.root_node(), &source, &file_str, config, functions);
202	        }
203	        Err(msg) => {
204	            errors.push(format!("{} in {}", msg, path.display()));
205	        }
206	    }
207	}
