296	pub fn make_function_info(
297	    node: tree_sitter::Node,
298	    source: &str,
299	    file: &str,
300	    config: &LangConfig,
301	) -> FunctionInfo {
302	    let start_line = node.start_position().row + 1;
303	    let end_line = node.end_position().row + 1;
304	    let hashes = collect_subtree_hashes(node, source, config);
305	    FunctionInfo {
306	        file: file.to_string(),
307	        start_line,
308	        end_line,
309	        node_hashes: hashes,
310	    }
