313	fn normalize_node_text(node: tree_sitter::Node, source: &str, config: &LangConfig) -> String {
314	    let kind = node.kind();
315	    if config.identifier_kinds.contains(&kind) {
316	        return "_ID".to_string();
317	    }
318	    if config.literal_kinds.contains(&kind) {
319	        return "_LIT".to_string();
320	    }
321	    let start = node.start_byte();
322	    let end = node.end_byte();
323	    source[start..end].to_string()
324	}
