326	pub fn build_normalized_subtree(
327	    node: tree_sitter::Node,
328	    source: &str,
329	    config: &LangConfig,
330	) -> String {
331	    if node.child_count() == 0 {
332	        return normalize_node_text(node, source, config);
333	    }
334	    let mut parts = vec![format!("({}:", node.kind())];
335	    let mut cursor = node.walk();
336	    for child in node.children(&mut cursor) {
337	        parts.push(build_normalized_subtree(child, source, config));
338	    }
339	    parts.push(")".to_string());
340	    parts.join("")
341	}
