249	pub fn execute_cli(
250	    paths: &[String],
251	    format_str: &str,
252	    lang: Option<&str>,
253	    config: Config,
254	    run_fn: impl Fn(&[String], &Config) -> RunResult,
255	) -> CliResult {
256	    let format = match parse_output_format(format_str) {
257	        Ok(f) => f,
258	        Err(e) => return cli_error(e),
259	    };
260	
261	    let lang_val = if let Some(lang) = lang {
262	        match validate_lang(lang) {
