264	            Err(e) => return cli_error(e),
265	        }
266	    } else {
267	        None
268	    };
269	
270	    let config = Config {
271	        format,
272	        lang: lang_val,
273	        ..config
274	    };
275	    let result = run_fn(paths, &config);
276	    run_result_to_cli(result, &config.format)
277	}
